using System;

class Program {
    static void Main() {
        string greeting = "Hello, World!";
        Console.WriteLine(greeting);
        Console.WriteLine(greeting.Length);
        Console.WriteLine(greeting.ToUpper());
    }
}

using System;

class Program {
    static void Main() {
        string name = "Alice";
        int score = 95;
        Console.WriteLine($"{name} scored {score}/100");
        Console.WriteLine($"Double: {score * 2}");
        Console.WriteLine($"Upper: {name.ToUpper()}");
    }
}

using System;

class Program {
    static void Main() {
        string s = "  Hello, Rust!  ";
        Console.WriteLine(s.Trim());
        Console.WriteLine(s.Trim().Replace("Rust", "C#"));
        Console.WriteLine(s.Trim().Contains("Hello"));
        Console.WriteLine(s.Trim().StartsWith("Hello"));
        Console.WriteLine(s.Trim().IndexOf(","));
    }
}

using System;

class Program {
    static void Main() {
        string s = "Hello, World!";
        Console.WriteLine(s.Substring(7, 5));
        Console.WriteLine(s[0..5]);  // C# range syntax
        Console.WriteLine(s[^6..]);  // from 6th from end
    }
}

using System;

class Program {
    static void Main() {
        string csv = "one,two,three,four";
        string[] parts = csv.Split(',');
        Console.WriteLine(parts.Length);
        Console.WriteLine(parts[1]);
        Console.WriteLine(String.Join(" | ", parts));
    }
}

using System;

class Program {
    static void Main() {
        string a = "Hello";
        string b = "hello";
        Console.WriteLine(a == b);
        Console.WriteLine(a.Equals(b, StringComparison.OrdinalIgnoreCase));
        Console.WriteLine(string.Compare(a, b));
    }
}

using System;

class Program {
    static void Main() {
        double price = 9.9;
        Console.WriteLine($"{price:F2}");    // 2 decimal places
        Console.WriteLine($"{price:C}");     // currency
        Console.WriteLine($"{1234567:N0}");  // number with commas
        Console.WriteLine($"{0.75:P}");      // percent
    }
}

using System;
using System.Text;

class Program {
    static void Main() {
        var sb = new StringBuilder();
        for (int i = 1; i <= 5; i++) {
            sb.Append(i);
            if (i < 5) sb.Append(", ");
        }
        Console.WriteLine(sb.ToString());
    }
}
